    { "kind": "timed",      "name": "...", "description": "...", "tip": "...", "equipment": "...", "tags": ["..."], "defaultSets": 3, "defaultDurationSec": 30, "defaultRestSec": 30 },
    { "kind": "continuous", "name": "...", "description": "...", "tip": "...", "equipment": "...", "tags": ["..."], "defaultDurationSec": 300 }
